-- Web Empire 800 Tools Program — Production Wave 2
-- Adds 100 deterministic formula tools across 10 new categories.
-- Safe, idempotent upserts. No destructive deletes.

begin;

insert into public.categories(
  slug, name_ar, name_en, description, icon, style_key, sort_order, is_active
)
values
  ('ecommerce-tools', 'أدوات التجارة الإلكترونية', 'E-commerce Tools', 'حاسبات المتاجر والمبيعات والمخزون والتحويل.', 'shopping-cart', 'violet', 200, true),
  ('real-estate-tools', 'أدوات العقار', 'Real Estate Tools', 'حاسبات الاستثمار العقاري والإيجار والتمويل.', 'building', 'gold', 210, true),
  ('travel-tools', 'أدوات السفر', 'Travel Tools', 'حاسبات ميزانية السفر والوقود والفنادق والمجموعات.', 'plane', 'cyan', 220, true),
  ('productivity-tools', 'أدوات الإنتاجية', 'Productivity Tools', 'حاسبات الوقت والإنجاز والاجتماعات والطاقة التشغيلية.', 'timer', 'violet', 230, true),
  ('creator-tools', 'أدوات صناع المحتوى', 'Creator Tools', 'حاسبات المشاهدات والتفاعل والرعاية والدخل الرقمي.', 'video', 'gold', 240, true),
  ('sales-tools', 'أدوات المبيعات', 'Sales Tools', 'حاسبات التحويل والصفقات والأهداف وخط المبيعات.', 'trending-up', 'cyan', 250, true),
  ('logistics-tools', 'أدوات اللوجستيات', 'Logistics Tools', 'حاسبات الشحن والمخزون والمستودعات والتوصيل.', 'truck', 'violet', 260, true),
  ('restaurant-tools', 'أدوات المطاعم', 'Restaurant Tools', 'حاسبات تكلفة الطعام والتسعير والعمالة والتشغيل.', 'utensils', 'gold', 270, true),
  ('freelancer-tools', 'أدوات المستقلين', 'Freelancer Tools', 'حاسبات التسعير والدخل والعمولات والطاقة الاستيعابية.', 'briefcase', 'cyan', 280, true),
  ('sustainability-tools', 'أدوات الاستدامة', 'Sustainability Tools', 'حاسبات الطاقة والانبعاثات والمياه والتوفير البيئي.', 'leaf', 'green', 290, true)
on conflict (slug) do update set
  name_ar = excluded.name_ar,
  name_en = excluded.name_en,
  description = excluded.description,
  icon = excluded.icon,
  style_key = excluded.style_key,
  sort_order = excluded.sort_order,
  is_active = true;

insert into public.category_translations(category_id, locale_id, name, description)
select category.id, locale.id, seed.name, seed.description
from (
  values
    ('ecommerce-tools', 'ar', 'أدوات التجارة الإلكترونية', 'حاسبات المتاجر والمبيعات والمخزون والتحويل.'),
    ('ecommerce-tools', 'en', 'E-commerce Tools', 'حاسبات المتاجر والمبيعات والمخزون والتحويل.'),
    ('real-estate-tools', 'ar', 'أدوات العقار', 'حاسبات الاستثمار العقاري والإيجار والتمويل.'),
    ('real-estate-tools', 'en', 'Real Estate Tools', 'حاسبات الاستثمار العقاري والإيجار والتمويل.'),
    ('travel-tools', 'ar', 'أدوات السفر', 'حاسبات ميزانية السفر والوقود والفنادق والمجموعات.'),
    ('travel-tools', 'en', 'Travel Tools', 'حاسبات ميزانية السفر والوقود والفنادق والمجموعات.'),
    ('productivity-tools', 'ar', 'أدوات الإنتاجية', 'حاسبات الوقت والإنجاز والاجتماعات والطاقة التشغيلية.'),
    ('productivity-tools', 'en', 'Productivity Tools', 'حاسبات الوقت والإنجاز والاجتماعات والطاقة التشغيلية.'),
    ('creator-tools', 'ar', 'أدوات صناع المحتوى', 'حاسبات المشاهدات والتفاعل والرعاية والدخل الرقمي.'),
    ('creator-tools', 'en', 'Creator Tools', 'حاسبات المشاهدات والتفاعل والرعاية والدخل الرقمي.'),
    ('sales-tools', 'ar', 'أدوات المبيعات', 'حاسبات التحويل والصفقات والأهداف وخط المبيعات.'),
    ('sales-tools', 'en', 'Sales Tools', 'حاسبات التحويل والصفقات والأهداف وخط المبيعات.'),
    ('logistics-tools', 'ar', 'أدوات اللوجستيات', 'حاسبات الشحن والمخزون والمستودعات والتوصيل.'),
    ('logistics-tools', 'en', 'Logistics Tools', 'حاسبات الشحن والمخزون والمستودعات والتوصيل.'),
    ('restaurant-tools', 'ar', 'أدوات المطاعم', 'حاسبات تكلفة الطعام والتسعير والعمالة والتشغيل.'),
    ('restaurant-tools', 'en', 'Restaurant Tools', 'حاسبات تكلفة الطعام والتسعير والعمالة والتشغيل.'),
    ('freelancer-tools', 'ar', 'أدوات المستقلين', 'حاسبات التسعير والدخل والعمولات والطاقة الاستيعابية.'),
    ('freelancer-tools', 'en', 'Freelancer Tools', 'حاسبات التسعير والدخل والعمولات والطاقة الاستيعابية.'),
    ('sustainability-tools', 'ar', 'أدوات الاستدامة', 'حاسبات الطاقة والانبعاثات والمياه والتوفير البيئي.'),
    ('sustainability-tools', 'en', 'Sustainability Tools', 'حاسبات الطاقة والانبعاثات والمياه والتوفير البيئي.')
) as seed(category_slug, locale_code, name, description)
join public.categories category on category.slug = seed.category_slug
join public.locales locale on locale.code = seed.locale_code
on conflict (category_id, locale_id) do update set
  name = excluded.name,
  description = excluded.description,
  updated_at = now();

create temporary table wave2_formula_tool_seed (
  category_slug text not null,
  slug text not null,
  title_ar text not null,
  title_en text not null,
  description_ar text not null,
  description_en text not null,
  runtime_config jsonb not null,
  input_fields jsonb not null,
  english_fields jsonb not null,
  submit_ar text not null,
  submit_en text not null,
  sort_order integer not null,
  is_featured boolean not null
) on commit drop;

insert into wave2_formula_tool_seed(
  category_slug, slug, title_ar, title_en, description_ar, description_en,
  runtime_config, input_fields, english_fields, submit_ar, submit_en,
  sort_order, is_featured
)
values
  ('ecommerce-tools', 'average-order-value-calculator', 'حاسبة متوسط قيمة الطلب', 'Average Order Value Calculator', 'احسب متوسط قيمة الطلب من الإيرادات وعدد الطلبات.', 'Calculate average order value from revenue and order count.', '{"expression":"revenue / orders","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"متوسط قيمة الطلب","resultLabelEn":"Average order value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"revenue","label":"إجمالي الإيرادات","type":"number","required":true,"step":0.01,"min":0},{"key":"orders","label":"عدد الطلبات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"revenue","label":"Total revenue","type":"number","required":true,"step":0.01,"min":0},{"key":"orders","label":"Orders","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2000, true),
  ('ecommerce-tools', 'cart-abandonment-rate-calculator', 'حاسبة معدل ترك السلة', 'Cart Abandonment Rate Calculator', 'احسب نسبة السلات التي لم تتحول إلى طلبات.', 'Calculate the percentage of carts that did not become orders.', '{"expression":"((carts - orders) / carts) * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل ترك السلة","resultLabelEn":"Cart abandonment rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"carts","label":"السلات المنشأة","type":"number","required":true,"step":1,"min":1},{"key":"orders","label":"الطلبات المكتملة","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"carts","label":"Created carts","type":"number","required":true,"step":1,"min":1},{"key":"orders","label":"Completed orders","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2001, true),
  ('ecommerce-tools', 'ecommerce-conversion-rate-calculator', 'حاسبة تحويل المتجر', 'E-commerce Conversion Rate Calculator', 'احسب نسبة الزوار الذين أتموا طلبًا.', 'Calculate the percentage of visitors who completed an order.', '{"expression":"orders / visitors * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل التحويل","resultLabelEn":"Conversion rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"orders","label":"عدد الطلبات","type":"number","required":true,"step":1,"min":0},{"key":"visitors","label":"عدد الزوار","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"orders","label":"Orders","type":"number","required":true,"step":1,"min":0},{"key":"visitors","label":"Visitors","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2002, false),
  ('ecommerce-tools', 'customer-lifetime-value-basic-calculator', 'حاسبة قيمة العميل مدى الحياة', 'Basic Customer Lifetime Value Calculator', 'قدّر قيمة العميل من متوسط الطلب والتكرار ومدة العلاقة.', 'Estimate customer lifetime value from order value, frequency, and lifespan.', '{"expression":"average_order_value * purchase_frequency * customer_lifespan","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"قيمة العميل التقديرية","resultLabelEn":"Estimated customer lifetime value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"average_order_value","label":"متوسط قيمة الطلب","type":"number","required":true,"step":0.01,"min":0},{"key":"purchase_frequency","label":"مرات الشراء سنويًا","type":"number","required":true,"step":0.01,"min":0},{"key":"customer_lifespan","label":"مدة العلاقة بالسنوات","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"average_order_value","label":"Average order value","type":"number","required":true,"step":0.01,"min":0},{"key":"purchase_frequency","label":"Purchases per year","type":"number","required":true,"step":0.01,"min":0},{"key":"customer_lifespan","label":"Customer lifespan in years","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2003, false),
  ('ecommerce-tools', 'ecommerce-return-rate-calculator', 'حاسبة معدل المرتجعات', 'E-commerce Return Rate Calculator', 'احسب نسبة الطلبات المرتجعة.', 'Calculate the percentage of returned orders.', '{"expression":"returned_orders / total_orders * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل المرتجعات","resultLabelEn":"Return rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"returned_orders","label":"الطلبات المرتجعة","type":"number","required":true,"step":1,"min":0},{"key":"total_orders","label":"إجمالي الطلبات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"returned_orders","label":"Returned orders","type":"number","required":true,"step":1,"min":0},{"key":"total_orders","label":"Total orders","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2004, false),
  ('ecommerce-tools', 'ecommerce-refund-rate-calculator', 'حاسبة معدل الاسترداد', 'Refund Rate Calculator', 'احسب قيمة المبالغ المستردة كنسبة من الإيراد.', 'Calculate refunded amount as a percentage of revenue.', '{"expression":"refund_amount / revenue * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل الاسترداد","resultLabelEn":"Refund rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"refund_amount","label":"المبالغ المستردة","type":"number","required":true,"step":0.01,"min":0},{"key":"revenue","label":"الإيرادات","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"refund_amount","label":"Refund amount","type":"number","required":true,"step":0.01,"min":0},{"key":"revenue","label":"Revenue","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2005, false),
  ('ecommerce-tools', 'shipping-cost-per-order-calculator', 'حاسبة شحن الطلب الواحد', 'Shipping Cost per Order Calculator', 'احسب متوسط تكلفة الشحن لكل طلب.', 'Calculate average shipping cost per order.', '{"expression":"shipping_cost / orders","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الشحن لكل طلب","resultLabelEn":"Shipping cost per order","decimals":2,"showEquation":true}'::jsonb, '[{"key":"shipping_cost","label":"إجمالي تكلفة الشحن","type":"number","required":true,"step":0.01,"min":0},{"key":"orders","label":"عدد الطلبات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"shipping_cost","label":"Total shipping cost","type":"number","required":true,"step":0.01,"min":0},{"key":"orders","label":"Orders","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2006, false),
  ('ecommerce-tools', 'inventory-turnover-calculator', 'حاسبة دوران المخزون', 'Inventory Turnover Calculator', 'احسب عدد مرات دوران المخزون خلال الفترة.', 'Calculate how many times inventory turned over in a period.', '{"expression":"cost_of_goods_sold / average_inventory","outputUnitAr":" مرة","outputUnitEn":" times","resultLabelAr":"دوران المخزون","resultLabelEn":"Inventory turnover","decimals":2,"showEquation":true}'::jsonb, '[{"key":"cost_of_goods_sold","label":"تكلفة البضاعة المباعة","type":"number","required":true,"step":0.01,"min":0},{"key":"average_inventory","label":"متوسط قيمة المخزون","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"cost_of_goods_sold","label":"Cost of goods sold","type":"number","required":true,"step":0.01,"min":0},{"key":"average_inventory","label":"Average inventory","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2007, false),
  ('ecommerce-tools', 'break-even-orders-calculator', 'حاسبة طلبات نقطة التعادل', 'Break-even Orders Calculator', 'قدّر عدد الطلبات اللازمة لتغطية التكاليف الثابتة.', 'Estimate orders needed to cover fixed costs.', '{"expression":"fixed_cost / (price_per_order - variable_cost_per_order)","outputUnitAr":" طلب","outputUnitEn":" orders","resultLabelAr":"طلبات نقطة التعادل","resultLabelEn":"Break-even orders","decimals":0,"showEquation":true}'::jsonb, '[{"key":"fixed_cost","label":"التكاليف الثابتة","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_order","label":"الإيراد لكل طلب","type":"number","required":true,"step":0.01,"min":0.01},{"key":"variable_cost_per_order","label":"التكلفة المتغيرة لكل طلب","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"fixed_cost","label":"Fixed cost","type":"number","required":true,"step":0.01,"min":0},{"key":"price_per_order","label":"Revenue per order","type":"number","required":true,"step":0.01,"min":0.01},{"key":"variable_cost_per_order","label":"Variable cost per order","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2008, false),
  ('ecommerce-tools', 'marketplace-commission-calculator', 'حاسبة عمولة المنصة', 'Marketplace Commission Calculator', 'احسب عمولة منصة البيع من إجمالي المبيعات.', 'Calculate marketplace commission from gross sales.', '{"expression":"sales * commission_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"عمولة المنصة","resultLabelEn":"Marketplace commission","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sales","label":"إجمالي المبيعات","type":"number","required":true,"step":0.01,"min":0},{"key":"commission_rate","label":"نسبة العمولة","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":15}]'::jsonb, '[{"key":"sales","label":"Gross sales","type":"number","required":true,"step":0.01,"min":0},{"key":"commission_rate","label":"Commission rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":15}]'::jsonb, 'احسب النتيجة', 'Calculate', 2009, false),
  ('real-estate-tools', 'rental-yield-calculator', 'حاسبة العائد الإيجاري', 'Rental Yield Calculator', 'احسب العائد الإيجاري السنوي كنسبة من قيمة العقار.', 'Calculate annual rental yield as a percentage of property value.', '{"expression":"annual_rent / property_value * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"العائد الإيجاري","resultLabelEn":"Rental yield","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_rent","label":"الإيجار السنوي","type":"number","required":true,"step":0.01,"min":0},{"key":"property_value","label":"قيمة العقار","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"annual_rent","label":"Annual rent","type":"number","required":true,"step":0.01,"min":0},{"key":"property_value","label":"Property value","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2010, true),
  ('real-estate-tools', 'cap-rate-calculator', 'حاسبة معدل الرسملة', 'Cap Rate Calculator', 'احسب معدل الرسملة من صافي الدخل التشغيلي وقيمة العقار.', 'Calculate capitalization rate from net operating income and property value.', '{"expression":"net_operating_income / property_value * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل الرسملة","resultLabelEn":"Capitalization rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"net_operating_income","label":"صافي الدخل التشغيلي","type":"number","required":true,"step":0.01,"min":0},{"key":"property_value","label":"قيمة العقار","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"net_operating_income","label":"Net operating income","type":"number","required":true,"step":0.01,"min":0},{"key":"property_value","label":"Property value","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2011, true),
  ('real-estate-tools', 'price-per-square-meter-calculator', 'حاسبة سعر المتر المربع', 'Price per Square Meter Calculator', 'احسب سعر المتر المربع للعقار.', 'Calculate property price per square meter.', '{"expression":"property_price / area_sqm","outputUnitAr":" ر.س/م²","outputUnitEn":" SAR/m²","resultLabelAr":"سعر المتر المربع","resultLabelEn":"Price per square meter","decimals":2,"showEquation":true}'::jsonb, '[{"key":"property_price","label":"سعر العقار","type":"number","required":true,"step":0.01,"min":0},{"key":"area_sqm","label":"المساحة بالمتر المربع","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"property_price","label":"Property price","type":"number","required":true,"step":0.01,"min":0},{"key":"area_sqm","label":"Area in square meters","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2012, false),
  ('real-estate-tools', 'mortgage-monthly-payment-calculator', 'حاسبة قسط التمويل العقاري', 'Mortgage Monthly Payment Calculator', 'قدّر القسط الشهري باستخدام أصل التمويل والمعدل والمدة.', 'Estimate monthly mortgage payment using principal, rate, and term.', '{"expression":"principal * monthly_rate * ((1 + monthly_rate) ^ months) / (((1 + monthly_rate) ^ months) - 1)","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"القسط الشهري التقديري","resultLabelEn":"Estimated monthly payment","decimals":2,"showEquation":true}'::jsonb, '[{"key":"principal","label":"مبلغ التمويل","type":"number","required":true,"step":0.01,"min":0.01},{"key":"monthly_rate","label":"المعدل الشهري كعدد عشري","type":"number","required":true,"step":0.01,"min":1e-06,"defaultValue":0.004},{"key":"months","label":"عدد الأشهر","type":"number","required":true,"step":1,"min":1,"defaultValue":240}]'::jsonb, '[{"key":"principal","label":"Loan principal","type":"number","required":true,"step":0.01,"min":0.01},{"key":"monthly_rate","label":"Monthly rate as decimal","type":"number","required":true,"step":0.01,"min":1e-06,"defaultValue":0.004},{"key":"months","label":"Months","type":"number","required":true,"step":1,"min":1,"defaultValue":240}]'::jsonb, 'احسب النتيجة', 'Calculate', 2013, false),
  ('real-estate-tools', 'down-payment-calculator', 'حاسبة الدفعة الأولى', 'Down Payment Calculator', 'احسب مبلغ الدفعة الأولى من سعر العقار والنسبة.', 'Calculate down payment from property price and rate.', '{"expression":"property_price * down_payment_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الدفعة الأولى","resultLabelEn":"Down payment","decimals":2,"showEquation":true}'::jsonb, '[{"key":"property_price","label":"سعر العقار","type":"number","required":true,"step":0.01,"min":0},{"key":"down_payment_rate","label":"نسبة الدفعة الأولى","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":10}]'::jsonb, '[{"key":"property_price","label":"Property price","type":"number","required":true,"step":0.01,"min":0},{"key":"down_payment_rate","label":"Down payment rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":10}]'::jsonb, 'احسب النتيجة', 'Calculate', 2014, false),
  ('real-estate-tools', 'loan-to-value-calculator', 'حاسبة نسبة التمويل إلى القيمة', 'Loan-to-Value Calculator', 'احسب نسبة مبلغ التمويل إلى قيمة العقار.', 'Calculate loan amount as a percentage of property value.', '{"expression":"loan_amount / property_value * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة التمويل إلى القيمة","resultLabelEn":"Loan-to-value ratio","decimals":2,"showEquation":true}'::jsonb, '[{"key":"loan_amount","label":"مبلغ التمويل","type":"number","required":true,"step":0.01,"min":0},{"key":"property_value","label":"قيمة العقار","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"loan_amount","label":"Loan amount","type":"number","required":true,"step":0.01,"min":0},{"key":"property_value","label":"Property value","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2015, false),
  ('real-estate-tools', 'property-appreciation-calculator', 'حاسبة نمو قيمة العقار', 'Property Appreciation Calculator', 'قدّر قيمة العقار مستقبلًا بمعدل نمو سنوي.', 'Estimate future property value using annual appreciation.', '{"expression":"current_value * ((1 + annual_rate / 100) ^ years)","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"القيمة المستقبلية","resultLabelEn":"Future value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"current_value","label":"القيمة الحالية","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"معدل النمو السنوي","type":"number","required":true,"step":0.01,"min":-100,"max":1000},{"key":"years","label":"عدد السنوات","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"current_value","label":"Current value","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_rate","label":"Annual appreciation rate","type":"number","required":true,"step":0.01,"min":-100,"max":1000},{"key":"years","label":"Years","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2016, false),
  ('real-estate-tools', 'rental-vacancy-loss-calculator', 'حاسبة خسارة الشغور', 'Rental Vacancy Loss Calculator', 'قدّر خسارة الإيجار الناتجة عن نسبة الشغور.', 'Estimate rental income loss caused by vacancy.', '{"expression":"annual_rent * vacancy_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"خسارة الشغور","resultLabelEn":"Vacancy loss","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_rent","label":"الإيجار السنوي المتوقع","type":"number","required":true,"step":0.01,"min":0},{"key":"vacancy_rate","label":"نسبة الشغور","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, '[{"key":"annual_rent","label":"Expected annual rent","type":"number","required":true,"step":0.01,"min":0},{"key":"vacancy_rate","label":"Vacancy rate","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 2017, false),
  ('real-estate-tools', 'property-management-fee-calculator', 'حاسبة رسوم إدارة العقار', 'Property Management Fee Calculator', 'احسب رسوم الإدارة كنسبة من الإيجار السنوي.', 'Calculate property management fees as a percentage of annual rent.', '{"expression":"annual_rent * fee_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"رسوم إدارة العقار","resultLabelEn":"Property management fee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_rent","label":"الإيجار السنوي","type":"number","required":true,"step":0.01,"min":0},{"key":"fee_rate","label":"نسبة رسوم الإدارة","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":5}]'::jsonb, '[{"key":"annual_rent","label":"Annual rent","type":"number","required":true,"step":0.01,"min":0},{"key":"fee_rate","label":"Management fee rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":5}]'::jsonb, 'احسب النتيجة', 'Calculate', 2018, false),
  ('real-estate-tools', 'real-estate-cash-roi-calculator', 'حاسبة عائد الاستثمار العقاري النقدي', 'Real Estate Cash ROI Calculator', 'احسب العائد الصافي على الاستثمار النقدي.', 'Calculate net return on cash invested.', '{"expression":"(annual_income - annual_expenses) / cash_invested * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"العائد النقدي","resultLabelEn":"Cash ROI","decimals":2,"showEquation":true}'::jsonb, '[{"key":"annual_income","label":"الدخل السنوي","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_expenses","label":"المصروفات السنوية","type":"number","required":true,"step":0.01,"min":0},{"key":"cash_invested","label":"النقد المستثمر","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"annual_income","label":"Annual income","type":"number","required":true,"step":0.01,"min":0},{"key":"annual_expenses","label":"Annual expenses","type":"number","required":true,"step":0.01,"min":0},{"key":"cash_invested","label":"Cash invested","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2019, false),
  ('travel-tools', 'trip-budget-per-day-calculator', 'حاسبة ميزانية السفر اليومية', 'Trip Budget per Day Calculator', 'قسّم ميزانية الرحلة على عدد الأيام.', 'Divide trip budget by the number of days.', '{"expression":"total_budget / days","outputUnitAr":" ر.س/يوم","outputUnitEn":" SAR/day","resultLabelAr":"الميزانية اليومية","resultLabelEn":"Daily budget","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_budget","label":"ميزانية الرحلة","type":"number","required":true,"step":0.01,"min":0},{"key":"days","label":"عدد الأيام","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"total_budget","label":"Trip budget","type":"number","required":true,"step":0.01,"min":0},{"key":"days","label":"Days","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2020, true),
  ('travel-tools', 'trip-fuel-cost-calculator', 'حاسبة وقود الرحلة', 'Trip Fuel Cost Calculator', 'احسب تكلفة الوقود من المسافة وكفاءة المركبة والسعر.', 'Calculate fuel cost from distance, efficiency, and fuel price.', '{"expression":"distance / fuel_efficiency * fuel_price","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الوقود","resultLabelEn":"Fuel cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"distance","label":"المسافة بالكيلومتر","type":"number","required":true,"step":0.01,"min":0},{"key":"fuel_efficiency","label":"كيلومتر لكل لتر","type":"number","required":true,"step":0.01,"min":0.01},{"key":"fuel_price","label":"سعر اللتر","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"distance","label":"Distance in km","type":"number","required":true,"step":0.01,"min":0},{"key":"fuel_efficiency","label":"Kilometers per liter","type":"number","required":true,"step":0.01,"min":0.01},{"key":"fuel_price","label":"Fuel price per liter","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2021, true),
  ('travel-tools', 'hotel-stay-total-calculator', 'حاسبة تكلفة الفندق', 'Hotel Stay Total Calculator', 'احسب تكلفة الإقامة من عدد الليالي وسعر الليلة.', 'Calculate hotel stay cost from nights and nightly rate.', '{"expression":"nights * nightly_rate","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"إجمالي الفندق","resultLabelEn":"Hotel total","decimals":2,"showEquation":true}'::jsonb, '[{"key":"nights","label":"عدد الليالي","type":"number","required":true,"step":1,"min":1},{"key":"nightly_rate","label":"سعر الليلة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"nights","label":"Nights","type":"number","required":true,"step":1,"min":1},{"key":"nightly_rate","label":"Nightly rate","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2022, false),
  ('travel-tools', 'travel-currency-budget-calculator', 'حاسبة تحويل ميزانية السفر', 'Travel Currency Budget Calculator', 'حوّل ميزانية السفر باستخدام سعر صرف تدخله.', 'Convert travel budget using an exchange rate.', '{"expression":"amount * exchange_rate","outputUnitAr":"","outputUnitEn":"","resultLabelAr":"المبلغ بعد التحويل","resultLabelEn":"Converted amount","decimals":2,"showEquation":true}'::jsonb, '[{"key":"amount","label":"المبلغ الأساسي","type":"number","required":true,"step":0.01,"min":0},{"key":"exchange_rate","label":"سعر الصرف","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"amount","label":"Base amount","type":"number","required":true,"step":0.01,"min":0},{"key":"exchange_rate","label":"Exchange rate","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2023, false),
  ('travel-tools', 'baggage-overweight-fee-calculator', 'حاسبة رسوم الوزن الزائد', 'Baggage Overweight Fee Calculator', 'احسب رسوم الأمتعة الزائدة حسب الكيلوجرام.', 'Calculate excess baggage fees by kilogram.', '{"expression":"extra_weight * fee_per_kg","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"رسوم الوزن الزائد","resultLabelEn":"Overweight baggage fee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"extra_weight","label":"الوزن الزائد بالكيلوجرام","type":"number","required":true,"step":0.01,"min":0},{"key":"fee_per_kg","label":"الرسوم لكل كيلوجرام","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"extra_weight","label":"Extra weight in kg","type":"number","required":true,"step":0.01,"min":0},{"key":"fee_per_kg","label":"Fee per kg","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2024, false),
  ('travel-tools', 'travel-time-calculator', 'حاسبة زمن الرحلة', 'Travel Time Calculator', 'قدّر زمن الرحلة من المسافة والسرعة المتوسطة.', 'Estimate travel time from distance and average speed.', '{"expression":"distance / average_speed","outputUnitAr":" ساعة","outputUnitEn":" hours","resultLabelAr":"زمن الرحلة","resultLabelEn":"Travel time","decimals":2,"showEquation":true}'::jsonb, '[{"key":"distance","label":"المسافة","type":"number","required":true,"step":0.01,"min":0},{"key":"average_speed","label":"السرعة المتوسطة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"distance","label":"Distance","type":"number","required":true,"step":0.01,"min":0},{"key":"average_speed","label":"Average speed","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2025, false),
  ('travel-tools', 'itinerary-hours-per-day-calculator', 'حاسبة ساعات البرنامج اليومية', 'Itinerary Hours per Day Calculator', 'وزّع ساعات الأنشطة على أيام الرحلة.', 'Distribute activity hours across trip days.', '{"expression":"total_activity_hours / days","outputUnitAr":" ساعة/يوم","outputUnitEn":" hours/day","resultLabelAr":"ساعات الأنشطة يوميًا","resultLabelEn":"Daily itinerary hours","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_activity_hours","label":"إجمالي ساعات الأنشطة","type":"number","required":true,"step":0.01,"min":0},{"key":"days","label":"عدد الأيام","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"total_activity_hours","label":"Total activity hours","type":"number","required":true,"step":0.01,"min":0},{"key":"days","label":"Days","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2026, false),
  ('travel-tools', 'group-trip-share-calculator', 'حاسبة حصة الفرد في الرحلة', 'Group Trip Share Calculator', 'قسّم تكلفة الرحلة بالتساوي على عدد المسافرين.', 'Split trip cost equally among travelers.', '{"expression":"total_cost / travelers","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"حصة الفرد","resultLabelEn":"Cost per traveler","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_cost","label":"إجمالي التكلفة","type":"number","required":true,"step":0.01,"min":0},{"key":"travelers","label":"عدد المسافرين","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"total_cost","label":"Total cost","type":"number","required":true,"step":0.01,"min":0},{"key":"travelers","label":"Travelers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2027, false),
  ('travel-tools', 'travel-insurance-cost-calculator', 'حاسبة تأمين السفر', 'Travel Insurance Cost Calculator', 'قدّر تكلفة تأمين السفر كنسبة من قيمة الرحلة.', 'Estimate travel insurance cost as a percentage of trip value.', '{"expression":"trip_cost * insurance_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة التأمين","resultLabelEn":"Insurance cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"trip_cost","label":"قيمة الرحلة","type":"number","required":true,"step":0.01,"min":0},{"key":"insurance_rate","label":"نسبة التأمين","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":4}]'::jsonb, '[{"key":"trip_cost","label":"Trip cost","type":"number","required":true,"step":0.01,"min":0},{"key":"insurance_rate","label":"Insurance rate","type":"number","required":true,"step":0.01,"min":0,"max":100,"defaultValue":4}]'::jsonb, 'احسب النتيجة', 'Calculate', 2028, false),
  ('travel-tools', 'visa-fees-total-calculator', 'حاسبة إجمالي رسوم التأشيرات', 'Visa Fees Total Calculator', 'احسب إجمالي رسوم التأشيرات لجميع المسافرين.', 'Calculate total visa fees for all travelers.', '{"expression":"visa_fee * travelers","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"إجمالي رسوم التأشيرات","resultLabelEn":"Total visa fees","decimals":2,"showEquation":true}'::jsonb, '[{"key":"visa_fee","label":"رسوم التأشيرة للفرد","type":"number","required":true,"step":0.01,"min":0},{"key":"travelers","label":"عدد المسافرين","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"visa_fee","label":"Visa fee per traveler","type":"number","required":true,"step":0.01,"min":0},{"key":"travelers","label":"Travelers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2029, false),
  ('productivity-tools', 'focus-ratio-calculator', 'حاسبة نسبة التركيز', 'Focus Ratio Calculator', 'احسب نسبة وقت التركيز من الوقت المتاح.', 'Calculate focused time as a percentage of available time.', '{"expression":"focus_minutes / available_minutes * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة التركيز","resultLabelEn":"Focus ratio","decimals":2,"showEquation":true}'::jsonb, '[{"key":"focus_minutes","label":"دقائق التركيز","type":"number","required":true,"step":0.01,"min":0},{"key":"available_minutes","label":"الدقائق المتاحة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"focus_minutes","label":"Focus minutes","type":"number","required":true,"step":0.01,"min":0},{"key":"available_minutes","label":"Available minutes","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2030, true),
