  ('productivity-tools', 'pomodoro-session-calculator', 'حاسبة جلسات بومودورو', 'Pomodoro Session Calculator', 'قدّر عدد جلسات التركيز داخل وقت العمل.', 'Estimate the number of focus sessions in available work time.', '{"expression":"work_minutes / session_minutes","outputUnitAr":" جلسة","outputUnitEn":" sessions","resultLabelAr":"عدد الجلسات","resultLabelEn":"Sessions","decimals":1,"showEquation":true}'::jsonb, '[{"key":"work_minutes","label":"وقت العمل بالدقائق","type":"number","required":true,"step":0.01,"min":0},{"key":"session_minutes","label":"مدة الجلسة","type":"number","required":true,"step":0.01,"min":1,"defaultValue":25}]'::jsonb, '[{"key":"work_minutes","label":"Work minutes","type":"number","required":true,"step":0.01,"min":0},{"key":"session_minutes","label":"Session minutes","type":"number","required":true,"step":0.01,"min":1,"defaultValue":25}]'::jsonb, 'احسب النتيجة', 'Calculate', 2032, false),
  ('productivity-tools', 'weekly-work-capacity-calculator', 'حاسبة الطاقة الأسبوعية', 'Weekly Work Capacity Calculator', 'احسب ساعات العمل المتاحة أسبوعيًا.', 'Calculate available work hours per week.', '{"expression":"hours_per_day * work_days","outputUnitAr":" ساعة","outputUnitEn":" hours","resultLabelAr":"الطاقة الأسبوعية","resultLabelEn":"Weekly capacity","decimals":2,"showEquation":true}'::jsonb, '[{"key":"hours_per_day","label":"ساعات العمل اليومية","type":"number","required":true,"step":0.01,"min":0,"max":24},{"key":"work_days","label":"أيام العمل","type":"number","required":true,"step":1,"min":0,"max":7}]'::jsonb, '[{"key":"hours_per_day","label":"Hours per day","type":"number","required":true,"step":0.01,"min":0,"max":24},{"key":"work_days","label":"Work days","type":"number","required":true,"step":1,"min":0,"max":7}]'::jsonb, 'احسب النتيجة', 'Calculate', 2033, false),
