  ('productivity-tools', 'meeting-cost-calculator', 'حاسبة تكلفة الاجتماع', 'Meeting Cost Calculator', 'احسب تكلفة الاجتماع من الحضور والأجر والمدة.', 'Calculate meeting cost from attendees, hourly rate, and duration.', '{"expression":"attendees * hourly_rate * duration_hours","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الاجتماع","resultLabelEn":"Meeting cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"attendees","label":"عدد الحضور","type":"number","required":true,"step":1,"min":1},{"key":"hourly_rate","label":"متوسط الأجر بالساعة","type":"number","required":true,"step":0.01,"min":0},{"key":"duration_hours","label":"مدة الاجتماع بالساعات","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"attendees","label":"Attendees","type":"number","required":true,"step":1,"min":1},{"key":"hourly_rate","label":"Average hourly rate","type":"number","required":true,"step":0.01,"min":0},{"key":"duration_hours","label":"Meeting duration in hours","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2035, false),
  ('productivity-tools', 'automation-time-saved-calculator', 'حاسبة الوقت الموفر بالأتمتة', 'Automation Time Saved Calculator', 'احسب الوقت الموفر من عدد مرات التشغيل والدقائق المحفوظة.', 'Calculate time saved from automation runs and minutes saved per run.', '{"expression":"automation_runs * minutes_saved_per_run / 60","outputUnitAr":" ساعة","outputUnitEn":" hours","resultLabelAr":"الوقت الموفر","resultLabelEn":"Time saved","decimals":2,"showEquation":true}'::jsonb, '[{"key":"automation_runs","label":"مرات التشغيل","type":"number","required":true,"step":1,"min":0},{"key":"minutes_saved_per_run","label":"الدقائق الموفرة لكل تشغيل","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"automation_runs","label":"Automation runs","type":"number","required":true,"step":1,"min":0},{"key":"minutes_saved_per_run","label":"Minutes saved per run","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2036, false),
  ('productivity-tools', 'team-utilization-rate-calculator', 'حاسبة استغلال وقت الفريق', 'Team Utilization Rate Calculator', 'احسب نسبة الساعات المنتجة من الساعات المتاحة.', 'Calculate productive hours as a percentage of available hours.', '{"expression":"productive_hours / available_hours * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل الاستغلال","resultLabelEn":"Utilization rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"productive_hours","label":"الساعات المنتجة","type":"number","required":true,"step":0.01,"min":0},{"key":"available_hours","label":"الساعات المتاحة","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"productive_hours","label":"Productive hours","type":"number","required":true,"step":0.01,"min":0},{"key":"available_hours","label":"Available hours","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2037, false),
  ('productivity-tools', 'productivity-output-per-hour-calculator', 'حاسبة الإنتاج لكل ساعة', 'Output per Hour Calculator', 'احسب عدد الوحدات المنجزة لكل ساعة.', 'Calculate completed output per hour.', '{"expression":"completed_units / work_hours","outputUnitAr":" وحدة/ساعة","outputUnitEn":" units/hour","resultLabelAr":"الإنتاج لكل ساعة","resultLabelEn":"Output per hour","decimals":2,"showEquation":true}'::jsonb, '[{"key":"completed_units","label":"الوحدات المكتملة","type":"number","required":true,"step":0.01,"min":0},{"key":"work_hours","label":"ساعات العمل","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"completed_units","label":"Completed units","type":"number","required":true,"step":0.01,"min":0},{"key":"work_hours","label":"Work hours","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2038, false),
  ('productivity-tools', 'deadline-buffer-calculator', 'حاسبة هامش الموعد النهائي', 'Deadline Buffer Calculator', 'احسب الأيام المتبقية بعد خصم مدة التنفيذ المطلوبة.', 'Calculate remaining buffer days after required execution time.', '{"expression":"deadline_days - required_days","outputUnitAr":" يوم","outputUnitEn":" days","resultLabelAr":"هامش الموعد","resultLabelEn":"Deadline buffer","decimals":1,"showEquation":true}'::jsonb, '[{"key":"deadline_days","label":"الأيام حتى الموعد","type":"number","required":true,"step":0.01,"min":0},{"key":"required_days","label":"أيام التنفيذ المطلوبة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"deadline_days","label":"Days until deadline","type":"number","required":true,"step":0.01,"min":0},{"key":"required_days","label":"Required work days","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2039, false),
  ('creator-tools', 'youtube-cpm-revenue-calculator', 'حاسبة دخل المشاهدات CPM', 'CPM Revenue Calculator', 'قدّر الإيراد من المشاهدات ومعدل CPM.', 'Estimate revenue from views and CPM.', '{"expression":"views / 1000 * cpm","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الإيراد التقديري","resultLabelEn":"Estimated revenue","decimals":2,"showEquation":true}'::jsonb, '[{"key":"views","label":"عدد المشاهدات","type":"number","required":true,"step":1,"min":0},{"key":"cpm","label":"العائد لكل ألف مشاهدة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"views","label":"Views","type":"number","required":true,"step":1,"min":0},{"key":"cpm","label":"Revenue per thousand views","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2040, true),
  ('creator-tools', 'social-engagement-rate-calculator', 'حاسبة معدل التفاعل', 'Social Engagement Rate Calculator', 'احسب التفاعل من الإعجابات والتعليقات والمشاركات.', 'Calculate engagement from likes, comments, and shares.', '{"expression":"(likes + comments + shares) / followers * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل التفاعل","resultLabelEn":"Engagement rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"likes","label":"الإعجابات","type":"number","required":true,"step":1,"min":0},{"key":"comments","label":"التعليقات","type":"number","required":true,"step":1,"min":0},{"key":"shares","label":"المشاركات","type":"number","required":true,"step":1,"min":0},{"key":"followers","label":"المتابعون","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"likes","label":"Likes","type":"number","required":true,"step":1,"min":0},{"key":"comments","label":"Comments","type":"number","required":true,"step":1,"min":0},{"key":"shares","label":"Shares","type":"number","required":true,"step":1,"min":0},{"key":"followers","label":"Followers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2041, true),
  ('creator-tools', 'follower-growth-rate-calculator', 'حاسبة نمو المتابعين', 'Follower Growth Rate Calculator', 'احسب نمو المتابعين بين فترتين.', 'Calculate follower growth between two periods.', '{"expression":"(new_followers - old_followers) / old_followers * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل النمو","resultLabelEn":"Growth rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"new_followers","label":"المتابعون حاليًا","type":"number","required":true,"step":1,"min":0},{"key":"old_followers","label":"المتابعون سابقًا","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"new_followers","label":"Current followers","type":"number","required":true,"step":1,"min":0},{"key":"old_followers","label":"Previous followers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2042, false),
  ('creator-tools', 'sponsorship-rate-calculator', 'حاسبة سعر الرعاية', 'Sponsorship Rate Calculator', 'قدّر سعر الرعاية من المتابعين وسعر الألف.', 'Estimate sponsorship price from followers and rate per thousand.', '{"expression":"followers / 1000 * rate_per_thousand","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"سعر الرعاية التقديري","resultLabelEn":"Estimated sponsorship rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"followers","label":"عدد المتابعين","type":"number","required":true,"step":1,"min":0},{"key":"rate_per_thousand","label":"السعر لكل ألف متابع","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"followers","label":"Followers","type":"number","required":true,"step":1,"min":0},{"key":"rate_per_thousand","label":"Rate per thousand followers","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2043, false),
  ('creator-tools', 'video-production-cost-calculator', 'حاسبة تكلفة إنتاج الفيديو', 'Video Production Cost Calculator', 'احسب تكلفة الفيديو من ساعات العمل والتكاليف الثابتة.', 'Calculate video cost from work hours and fixed expenses.', '{"expression":"work_hours * hourly_cost + fixed_cost","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الإنتاج","resultLabelEn":"Production cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"work_hours","label":"ساعات العمل","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_cost","label":"تكلفة الساعة","type":"number","required":true,"step":0.01,"min":0},{"key":"fixed_cost","label":"تكاليف ثابتة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"work_hours","label":"Work hours","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_cost","label":"Hourly cost","type":"number","required":true,"step":0.01,"min":0},{"key":"fixed_cost","label":"Fixed cost","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2044, false),
