  ('creator-tools', 'thumbnail-click-through-rate-calculator', 'حاسبة CTR للصورة المصغرة', 'Thumbnail CTR Calculator', 'احسب نسبة النقر إلى مرات الظهور.', 'Calculate clicks as a percentage of impressions.', '{"expression":"clicks / impressions * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة النقر","resultLabelEn":"Click-through rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"clicks","label":"النقرات","type":"number","required":true,"step":1,"min":0},{"key":"impressions","label":"مرات الظهور","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"clicks","label":"Clicks","type":"number","required":true,"step":1,"min":0},{"key":"impressions","label":"Impressions","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2047, false),
  ('creator-tools', 'affiliate-revenue-calculator', 'حاسبة دخل التسويق بالعمولة', 'Affiliate Revenue Calculator', 'قدّر الدخل من النقرات والتحويل والعمولة.', 'Estimate affiliate income from clicks, conversion, and commission.', '{"expression":"clicks * conversion_rate / 100 * commission_per_sale","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"الدخل التقديري","resultLabelEn":"Estimated affiliate revenue","decimals":2,"showEquation":true}'::jsonb, '[{"key":"clicks","label":"النقرات","type":"number","required":true,"step":1,"min":0},{"key":"conversion_rate","label":"نسبة التحويل","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"commission_per_sale","label":"عمولة العملية","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"clicks","label":"Clicks","type":"number","required":true,"step":1,"min":0},{"key":"conversion_rate","label":"Conversion rate","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"commission_per_sale","label":"Commission per sale","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2048, false),
  ('creator-tools', 'newsletter-open-rate-calculator', 'حاسبة معدل فتح النشرة', 'Newsletter Open Rate Calculator', 'احسب نسبة الرسائل المفتوحة من الرسائل المستلمة.', 'Calculate opened emails as a percentage of delivered emails.', '{"expression":"opens / delivered * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل الفتح","resultLabelEn":"Open rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"opens","label":"الرسائل المفتوحة","type":"number","required":true,"step":1,"min":0},{"key":"delivered","label":"الرسائل المستلمة","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"opens","label":"Opens","type":"number","required":true,"step":1,"min":0},{"key":"delivered","label":"Delivered","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2049, false),
  ('sales-tools', 'sales-conversion-rate-calculator', 'حاسبة تحويل المبيعات', 'Sales Conversion Rate Calculator', 'احسب نسبة العملاء المحتملين الذين أصبحوا صفقات.', 'Calculate leads that became closed deals.', '{"expression":"closed_deals / leads * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل التحويل","resultLabelEn":"Sales conversion rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"closed_deals","label":"الصفقات المغلقة","type":"number","required":true,"step":1,"min":0},{"key":"leads","label":"العملاء المحتملون","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"closed_deals","label":"Closed deals","type":"number","required":true,"step":1,"min":0},{"key":"leads","label":"Leads","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2050, true),
  ('sales-tools', 'average-deal-size-calculator', 'حاسبة متوسط حجم الصفقة', 'Average Deal Size Calculator', 'احسب متوسط قيمة الصفقة.', 'Calculate average deal value.', '{"expression":"revenue / deals","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"متوسط حجم الصفقة","resultLabelEn":"Average deal size","decimals":2,"showEquation":true}'::jsonb, '[{"key":"revenue","label":"إيرادات الصفقات","type":"number","required":true,"step":0.01,"min":0},{"key":"deals","label":"عدد الصفقات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"revenue","label":"Deal revenue","type":"number","required":true,"step":0.01,"min":0},{"key":"deals","label":"Deals","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2051, true),
