  ('sales-tools', 'upsell-rate-calculator', 'حاسبة معدل البيع الإضافي', 'Upsell Rate Calculator', 'احسب نسبة العملاء الذين اشتروا ترقية أو إضافة.', 'Calculate customers who accepted an upsell.', '{"expression":"upsell_customers / total_customers * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل البيع الإضافي","resultLabelEn":"Upsell rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"upsell_customers","label":"عملاء البيع الإضافي","type":"number","required":true,"step":1,"min":0},{"key":"total_customers","label":"إجمالي العملاء","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"upsell_customers","label":"Upsell customers","type":"number","required":true,"step":1,"min":0},{"key":"total_customers","label":"Total customers","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2056, false),
