  ('sales-tools', 'sales-commission-calculator', 'حاسبة عمولة المبيعات', 'Sales Commission Calculator', 'احسب عمولة مندوب المبيعات.', 'Calculate sales representative commission.', '{"expression":"sales * commission_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"عمولة المبيعات","resultLabelEn":"Sales commission","decimals":2,"showEquation":true}'::jsonb, '[{"key":"sales","label":"قيمة المبيعات","type":"number","required":true,"step":0.01,"min":0},{"key":"commission_rate","label":"نسبة العمولة","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, '[{"key":"sales","label":"Sales value","type":"number","required":true,"step":0.01,"min":0},{"key":"commission_rate","label":"Commission rate","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 2058, false),
