  ('logistics-tools', 'freight-cost-per-kg-calculator', 'حاسبة تكلفة الشحن لكل كيلوجرام', 'Freight Cost per Kilogram Calculator', 'احسب تكلفة الشحن لكل كيلوجرام.', 'Calculate freight cost per kilogram.', '{"expression":"total_freight_cost / total_weight","outputUnitAr":" ر.س/كجم","outputUnitEn":" SAR/kg","resultLabelAr":"التكلفة لكل كيلوجرام","resultLabelEn":"Cost per kilogram","decimals":2,"showEquation":true}'::jsonb, '[{"key":"total_freight_cost","label":"إجمالي تكلفة الشحن","type":"number","required":true,"step":0.01,"min":0},{"key":"total_weight","label":"إجمالي الوزن بالكيلوجرام","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"total_freight_cost","label":"Total freight cost","type":"number","required":true,"step":0.01,"min":0},{"key":"total_weight","label":"Total weight in kg","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2060, true),
  ('logistics-tools', 'delivery-cost-per-order-calculator', 'حاسبة تكلفة التوصيل لكل طلب', 'Delivery Cost per Order Calculator', 'احسب متوسط تكلفة التوصيل للطلب.', 'Calculate average delivery cost per order.', '{"expression":"delivery_cost / orders","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة التوصيل للطلب","resultLabelEn":"Delivery cost per order","decimals":2,"showEquation":true}'::jsonb, '[{"key":"delivery_cost","label":"إجمالي تكلفة التوصيل","type":"number","required":true,"step":0.01,"min":0},{"key":"orders","label":"عدد الطلبات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"delivery_cost","label":"Total delivery cost","type":"number","required":true,"step":0.01,"min":0},{"key":"orders","label":"Orders","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2061, true),
