  ('logistics-tools', 'order-accuracy-rate-calculator', 'حاسبة دقة الطلبات', 'Order Accuracy Rate Calculator', 'احسب نسبة الطلبات الصحيحة دون أخطاء.', 'Calculate accurate orders as a percentage of total orders.', '{"expression":"accurate_orders / total_orders * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"دقة الطلبات","resultLabelEn":"Order accuracy rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"accurate_orders","label":"الطلبات الصحيحة","type":"number","required":true,"step":1,"min":0},{"key":"total_orders","label":"إجمالي الطلبات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"accurate_orders","label":"Accurate orders","type":"number","required":true,"step":1,"min":0},{"key":"total_orders","label":"Total orders","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2064, false),
  ('logistics-tools', 'on-time-delivery-rate-calculator', 'حاسبة التوصيل في الموعد', 'On-time Delivery Rate Calculator', 'احسب نسبة الطلبات التي وصلت في موعدها.', 'Calculate deliveries completed on time.', '{"expression":"on_time_deliveries / total_deliveries * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل التوصيل في الموعد","resultLabelEn":"On-time delivery rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"on_time_deliveries","label":"التوصيلات في الموعد","type":"number","required":true,"step":1,"min":0},{"key":"total_deliveries","label":"إجمالي التوصيلات","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"on_time_deliveries","label":"On-time deliveries","type":"number","required":true,"step":1,"min":0},{"key":"total_deliveries","label":"Total deliveries","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2065, false),
  ('logistics-tools', 'inventory-carrying-cost-calculator', 'حاسبة تكلفة الاحتفاظ بالمخزون', 'Inventory Carrying Cost Calculator', 'احسب تكلفة الاحتفاظ بالمخزون كنسبة سنوية.', 'Calculate annual inventory carrying cost.', '{"expression":"average_inventory * carrying_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"تكلفة الاحتفاظ بالمخزون","resultLabelEn":"Inventory carrying cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"average_inventory","label":"متوسط قيمة المخزون","type":"number","required":true,"step":0.01,"min":0},{"key":"carrying_rate","label":"نسبة تكلفة الاحتفاظ","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, '[{"key":"average_inventory","label":"Average inventory value","type":"number","required":true,"step":0.01,"min":0},{"key":"carrying_rate","label":"Carrying cost rate","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 2066, false),
  ('logistics-tools', 'reorder-point-calculator', 'حاسبة نقطة إعادة الطلب', 'Reorder Point Calculator', 'احسب نقطة إعادة الطلب من الطلب اليومي ومدة التوريد ومخزون الأمان.', 'Calculate reorder point from daily demand, lead time, and safety stock.', '{"expression":"daily_demand * lead_time_days + safety_stock","outputUnitAr":" وحدة","outputUnitEn":" units","resultLabelAr":"نقطة إعادة الطلب","resultLabelEn":"Reorder point","decimals":0,"showEquation":true}'::jsonb, '[{"key":"daily_demand","label":"الطلب اليومي","type":"number","required":true,"step":0.01,"min":0},{"key":"lead_time_days","label":"مدة التوريد بالأيام","type":"number","required":true,"step":0.01,"min":0},{"key":"safety_stock","label":"مخزون الأمان","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"daily_demand","label":"Daily demand","type":"number","required":true,"step":0.01,"min":0},{"key":"lead_time_days","label":"Lead time in days","type":"number","required":true,"step":0.01,"min":0},{"key":"safety_stock","label":"Safety stock","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2067, false),
  ('logistics-tools', 'safety-stock-calculator', 'حاسبة مخزون الأمان', 'Safety Stock Calculator', 'قدّر مخزون الأمان من الطلب ومدد التوريد القصوى والمتوسطة.', 'Estimate safety stock from maximum and average demand and lead time.', '{"expression":"max_daily_demand * max_lead_time - average_daily_demand * average_lead_time","outputUnitAr":" وحدة","outputUnitEn":" units","resultLabelAr":"مخزون الأمان","resultLabelEn":"Safety stock","decimals":0,"showEquation":true}'::jsonb, '[{"key":"max_daily_demand","label":"أقصى طلب يومي","type":"number","required":true,"step":0.01,"min":0},{"key":"max_lead_time","label":"أقصى مدة توريد","type":"number","required":true,"step":0.01,"min":0},{"key":"average_daily_demand","label":"متوسط الطلب اليومي","type":"number","required":true,"step":0.01,"min":0},{"key":"average_lead_time","label":"متوسط مدة التوريد","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"max_daily_demand","label":"Maximum daily demand","type":"number","required":true,"step":0.01,"min":0},{"key":"max_lead_time","label":"Maximum lead time","type":"number","required":true,"step":0.01,"min":0},{"key":"average_daily_demand","label":"Average daily demand","type":"number","required":true,"step":0.01,"min":0},{"key":"average_lead_time","label":"Average lead time","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2068, false),
