  ('freelancer-tools', 'freelancer-hourly-rate-calculator', 'حاسبة سعر ساعة المستقل', 'Freelancer Hourly Rate Calculator', 'احسب سعر الساعة المطلوب للوصول إلى دخل مستهدف.', 'Calculate required hourly rate for a target income.', '{"expression":"target_income / (billable_hours_per_month * months)","outputUnitAr":" ر.س/ساعة","outputUnitEn":" SAR/hour","resultLabelAr":"سعر الساعة المطلوب","resultLabelEn":"Required hourly rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"target_income","label":"الدخل المستهدف","type":"number","required":true,"step":0.01,"min":0},{"key":"billable_hours_per_month","label":"الساعات القابلة للفوترة شهريًا","type":"number","required":true,"step":0.01,"min":0.01},{"key":"months","label":"عدد الأشهر","type":"number","required":true,"step":1,"min":1,"defaultValue":12}]'::jsonb, '[{"key":"target_income","label":"Target income","type":"number","required":true,"step":0.01,"min":0},{"key":"billable_hours_per_month","label":"Billable hours per month","type":"number","required":true,"step":0.01,"min":0.01},{"key":"months","label":"Months","type":"number","required":true,"step":1,"min":1,"defaultValue":12}]'::jsonb, 'احسب النتيجة', 'Calculate', 2080, true),
  ('freelancer-tools', 'freelance-project-price-calculator', 'حاسبة سعر المشروع', 'Freelance Project Price Calculator', 'احسب سعر المشروع من الساعات وسعر الساعة.', 'Calculate project price from estimated hours and hourly rate.', '{"expression":"estimated_hours * hourly_rate","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"سعر المشروع","resultLabelEn":"Project price","decimals":2,"showEquation":true}'::jsonb, '[{"key":"estimated_hours","label":"الساعات المقدرة","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_rate","label":"سعر الساعة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"estimated_hours","label":"Estimated hours","type":"number","required":true,"step":0.01,"min":0},{"key":"hourly_rate","label":"Hourly rate","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2081, true),
  ('freelancer-tools', 'freelancer-tax-reserve-calculator', 'حاسبة مخصص الضريبة للمستقل', 'Freelancer Tax Reserve Calculator', 'احسب المبلغ المقترح تخصيصه للضريبة.', 'Calculate suggested tax reserve from income.', '{"expression":"income * tax_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"مخصص الضريبة","resultLabelEn":"Tax reserve","decimals":2,"showEquation":true}'::jsonb, '[{"key":"income","label":"الدخل","type":"number","required":true,"step":0.01,"min":0},{"key":"tax_rate","label":"نسبة المخصص","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, '[{"key":"income","label":"Income","type":"number","required":true,"step":0.01,"min":0},{"key":"tax_rate","label":"Reserve rate","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 2082, false),
  ('freelancer-tools', 'freelance-platform-fee-calculator', 'حاسبة رسوم منصة العمل الحر', 'Freelance Platform Fee Calculator', 'احسب رسوم المنصة من قيمة المشروع.', 'Calculate platform fee from project value.', '{"expression":"gross_amount * platform_fee_rate / 100","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"رسوم المنصة","resultLabelEn":"Platform fee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"gross_amount","label":"قيمة المشروع","type":"number","required":true,"step":0.01,"min":0},{"key":"platform_fee_rate","label":"نسبة رسوم المنصة","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, '[{"key":"gross_amount","label":"Project value","type":"number","required":true,"step":0.01,"min":0},{"key":"platform_fee_rate","label":"Platform fee rate","type":"number","required":true,"step":0.01,"min":0,"max":100}]'::jsonb, 'احسب النتيجة', 'Calculate', 2083, false),
  ('freelancer-tools', 'net-freelance-income-calculator', 'حاسبة صافي دخل المستقل', 'Net Freelance Income Calculator', 'احسب صافي الدخل بعد المصروفات والمخصصات.', 'Calculate net freelance income after expenses and reserves.', '{"expression":"gross_income - expenses - tax_reserve","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"صافي الدخل","resultLabelEn":"Net income","decimals":2,"showEquation":true}'::jsonb, '[{"key":"gross_income","label":"الدخل الإجمالي","type":"number","required":true,"step":0.01,"min":0},{"key":"expenses","label":"المصروفات","type":"number","required":true,"step":0.01,"min":0},{"key":"tax_reserve","label":"مخصص الضريبة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"gross_income","label":"Gross income","type":"number","required":true,"step":0.01,"min":0},{"key":"expenses","label":"Expenses","type":"number","required":true,"step":0.01,"min":0},{"key":"tax_reserve","label":"Tax reserve","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2084, false),
  ('freelancer-tools', 'proposal-win-rate-calculator', 'حاسبة نجاح العروض', 'Proposal Win Rate Calculator', 'احسب نسبة العروض التي تحولت إلى مشاريع.', 'Calculate proposals that became projects.', '{"expression":"won_projects / sent_proposals * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل نجاح العروض","resultLabelEn":"Proposal win rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"won_projects","label":"المشاريع الفائزة","type":"number","required":true,"step":1,"min":0},{"key":"sent_proposals","label":"العروض المرسلة","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"won_projects","label":"Won projects","type":"number","required":true,"step":1,"min":0},{"key":"sent_proposals","label":"Sent proposals","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2085, false),
  ('freelancer-tools', 'effective-hourly-rate-calculator', 'حاسبة سعر الساعة الفعلي', 'Effective Hourly Rate Calculator', 'احسب الدخل الفعلي لكل ساعة عمل.', 'Calculate actual income earned per hour.', '{"expression":"net_income / actual_hours","outputUnitAr":" ر.س/ساعة","outputUnitEn":" SAR/hour","resultLabelAr":"سعر الساعة الفعلي","resultLabelEn":"Effective hourly rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"net_income","label":"صافي الدخل","type":"number","required":true,"step":0.01,"min":0},{"key":"actual_hours","label":"ساعات العمل الفعلية","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"net_income","label":"Net income","type":"number","required":true,"step":0.01,"min":0},{"key":"actual_hours","label":"Actual work hours","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2086, false),
  ('freelancer-tools', 'retainer-contract-value-calculator', 'حاسبة قيمة عقد الاشتراك', 'Retainer Contract Value Calculator', 'احسب القيمة الكلية لعقد شهري ممتد.', 'Calculate total value of a monthly retainer.', '{"expression":"monthly_fee * months","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"قيمة العقد","resultLabelEn":"Contract value","decimals":2,"showEquation":true}'::jsonb, '[{"key":"monthly_fee","label":"الرسوم الشهرية","type":"number","required":true,"step":0.01,"min":0},{"key":"months","label":"مدة العقد بالأشهر","type":"number","required":true,"step":1,"min":1}]'::jsonb, '[{"key":"monthly_fee","label":"Monthly fee","type":"number","required":true,"step":0.01,"min":0},{"key":"months","label":"Contract months","type":"number","required":true,"step":1,"min":1}]'::jsonb, 'احسب النتيجة', 'Calculate', 2087, false),
  ('freelancer-tools', 'late-payment-fee-calculator', 'حاسبة غرامة تأخر السداد', 'Late Payment Fee Calculator', 'احسب غرامة التأخير حسب النسبة وعدد الأيام.', 'Calculate late payment fee from rate and overdue days.', '{"expression":"invoice_amount * monthly_late_rate / 100 * overdue_days / 30","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"غرامة التأخير","resultLabelEn":"Late fee","decimals":2,"showEquation":true}'::jsonb, '[{"key":"invoice_amount","label":"قيمة الفاتورة","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_late_rate","label":"نسبة التأخير الشهرية","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"overdue_days","label":"أيام التأخير","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"invoice_amount","label":"Invoice amount","type":"number","required":true,"step":0.01,"min":0},{"key":"monthly_late_rate","label":"Monthly late rate","type":"number","required":true,"step":0.01,"min":0,"max":100},{"key":"overdue_days","label":"Overdue days","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2088, false),
  ('freelancer-tools', 'freelancer-project-capacity-calculator', 'حاسبة طاقة المشاريع', 'Freelancer Project Capacity Calculator', 'قدّر عدد المشاريع الممكن تنفيذها ضمن الساعات المتاحة.', 'Estimate project capacity from available hours.', '{"expression":"available_hours / hours_per_project","outputUnitAr":" مشروع","outputUnitEn":" projects","resultLabelAr":"طاقة المشاريع","resultLabelEn":"Project capacity","decimals":1,"showEquation":true}'::jsonb, '[{"key":"available_hours","label":"الساعات المتاحة","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_project","label":"الساعات لكل مشروع","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"available_hours","label":"Available hours","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_project","label":"Hours per project","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2089, false),
  ('sustainability-tools', 'electricity-carbon-emissions-calculator', 'حاسبة انبعاثات الكهرباء', 'Electricity Carbon Emissions Calculator', 'قدّر الانبعاثات من استهلاك الكهرباء ومعامل الانبعاث.', 'Estimate emissions from electricity use and emission factor.', '{"expression":"electricity_kwh * emission_factor","outputUnitAr":" كجم CO₂","outputUnitEn":" kg CO₂","resultLabelAr":"الانبعاثات التقديرية","resultLabelEn":"Estimated emissions","decimals":2,"showEquation":true}'::jsonb, '[{"key":"electricity_kwh","label":"استهلاك الكهرباء ك.و.س","type":"number","required":true,"step":0.01,"min":0},{"key":"emission_factor","label":"معامل الانبعاث كجم/ك.و.س","type":"number","required":true,"step":0.01,"min":0,"defaultValue":0.5}]'::jsonb, '[{"key":"electricity_kwh","label":"Electricity use in kWh","type":"number","required":true,"step":0.01,"min":0},{"key":"emission_factor","label":"Emission factor kg/kWh","type":"number","required":true,"step":0.01,"min":0,"defaultValue":0.5}]'::jsonb, 'احسب النتيجة', 'Calculate', 2090, true),
  ('sustainability-tools', 'fuel-carbon-emissions-calculator', 'حاسبة انبعاثات الوقود', 'Fuel Carbon Emissions Calculator', 'قدّر انبعاثات الوقود من عدد اللترات والمعامل.', 'Estimate fuel emissions from liters and emission factor.', '{"expression":"fuel_liters * emission_factor","outputUnitAr":" كجم CO₂","outputUnitEn":" kg CO₂","resultLabelAr":"انبعاثات الوقود","resultLabelEn":"Fuel emissions","decimals":2,"showEquation":true}'::jsonb, '[{"key":"fuel_liters","label":"كمية الوقود باللتر","type":"number","required":true,"step":0.01,"min":0},{"key":"emission_factor","label":"معامل الانبعاث كجم/لتر","type":"number","required":true,"step":0.01,"min":0,"defaultValue":2.31}]'::jsonb, '[{"key":"fuel_liters","label":"Fuel liters","type":"number","required":true,"step":0.01,"min":0},{"key":"emission_factor","label":"Emission factor kg/liter","type":"number","required":true,"step":0.01,"min":0,"defaultValue":2.31}]'::jsonb, 'احسب النتيجة', 'Calculate', 2091, true),
  ('sustainability-tools', 'solar-energy-savings-calculator', 'حاسبة توفير الطاقة الشمسية', 'Solar Energy Savings Calculator', 'احسب قيمة الكهرباء التي وفرتها الطاقة الشمسية.', 'Calculate electricity cost saved by solar generation.', '{"expression":"generated_kwh * electricity_price","outputUnitAr":" ر.س","outputUnitEn":" SAR","resultLabelAr":"قيمة التوفير","resultLabelEn":"Solar savings","decimals":2,"showEquation":true}'::jsonb, '[{"key":"generated_kwh","label":"الطاقة المنتجة ك.و.س","type":"number","required":true,"step":0.01,"min":0},{"key":"electricity_price","label":"سعر الكيلوواط ساعة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"generated_kwh","label":"Generated kWh","type":"number","required":true,"step":0.01,"min":0},{"key":"electricity_price","label":"Electricity price per kWh","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2092, false),
  ('sustainability-tools', 'water-savings-calculator', 'حاسبة توفير المياه', 'Water Savings Calculator', 'احسب إجمالي المياه الموفرة خلال مدة.', 'Calculate total water saved over time.', '{"expression":"liters_saved_per_day * days","outputUnitAr":" لتر","outputUnitEn":" liters","resultLabelAr":"إجمالي المياه الموفرة","resultLabelEn":"Total water saved","decimals":2,"showEquation":true}'::jsonb, '[{"key":"liters_saved_per_day","label":"اللترات الموفرة يوميًا","type":"number","required":true,"step":0.01,"min":0},{"key":"days","label":"عدد الأيام","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"liters_saved_per_day","label":"Liters saved per day","type":"number","required":true,"step":0.01,"min":0},{"key":"days","label":"Days","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2093, false),
  ('sustainability-tools', 'recycling-rate-calculator', 'حاسبة معدل إعادة التدوير', 'Recycling Rate Calculator', 'احسب نسبة النفايات المعاد تدويرها.', 'Calculate recycled waste as a percentage of total waste.', '{"expression":"recycled_waste / total_waste * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"معدل إعادة التدوير","resultLabelEn":"Recycling rate","decimals":2,"showEquation":true}'::jsonb, '[{"key":"recycled_waste","label":"النفايات المعاد تدويرها","type":"number","required":true,"step":0.01,"min":0},{"key":"total_waste","label":"إجمالي النفايات","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, '[{"key":"recycled_waste","label":"Recycled waste","type":"number","required":true,"step":0.01,"min":0},{"key":"total_waste","label":"Total waste","type":"number","required":true,"step":0.01,"min":0.01}]'::jsonb, 'احسب النتيجة', 'Calculate', 2094, false),
  ('sustainability-tools', 'paper-reams-saved-calculator', 'حاسبة رزم الورق الموفرة', 'Paper Reams Saved Calculator', 'قدّر عدد رزم الورق التي تم توفيرها رقميًا.', 'Estimate paper reams saved through digital pages.', '{"expression":"digital_pages / 500","outputUnitAr":" رزمة","outputUnitEn":" reams","resultLabelAr":"رزم الورق الموفرة","resultLabelEn":"Paper reams saved","decimals":2,"showEquation":true}'::jsonb, '[{"key":"digital_pages","label":"عدد الصفحات الرقمية","type":"number","required":true,"step":1,"min":0}]'::jsonb, '[{"key":"digital_pages","label":"Digital pages","type":"number","required":true,"step":1,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2095, false),
  ('sustainability-tools', 'tree-offset-calculator', 'حاسبة الأشجار اللازمة للتعويض', 'Tree Offset Calculator', 'قدّر عدد الأشجار اللازمة لتعويض كمية انبعاثات.', 'Estimate trees required to offset emissions.', '{"expression":"annual_emissions / tree_absorption","outputUnitAr":" شجرة","outputUnitEn":" trees","resultLabelAr":"الأشجار اللازمة","resultLabelEn":"Trees required","decimals":1,"showEquation":true}'::jsonb, '[{"key":"annual_emissions","label":"الانبعاثات السنوية كجم","type":"number","required":true,"step":0.01,"min":0},{"key":"tree_absorption","label":"امتصاص الشجرة سنويًا كجم","type":"number","required":true,"step":0.01,"min":0.01,"defaultValue":22}]'::jsonb, '[{"key":"annual_emissions","label":"Annual emissions in kg","type":"number","required":true,"step":0.01,"min":0},{"key":"tree_absorption","label":"Annual absorption per tree","type":"number","required":true,"step":0.01,"min":0.01,"defaultValue":22}]'::jsonb, 'احسب النتيجة', 'Calculate', 2096, false),
  ('sustainability-tools', 'energy-efficiency-improvement-calculator', 'حاسبة تحسن كفاءة الطاقة', 'Energy Efficiency Improvement Calculator', 'احسب انخفاض استهلاك الطاقة كنسبة مئوية.', 'Calculate energy use reduction as a percentage.', '{"expression":"(old_consumption - new_consumption) / old_consumption * 100","outputUnitAr":"%","outputUnitEn":"%","resultLabelAr":"نسبة التحسن","resultLabelEn":"Efficiency improvement","decimals":2,"showEquation":true}'::jsonb, '[{"key":"old_consumption","label":"الاستهلاك السابق","type":"number","required":true,"step":0.01,"min":0.01},{"key":"new_consumption","label":"الاستهلاك الجديد","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"old_consumption","label":"Previous consumption","type":"number","required":true,"step":0.01,"min":0.01},{"key":"new_consumption","label":"New consumption","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2097, false),
  ('sustainability-tools', 'appliance-annual-energy-cost-calculator', 'حاسبة تكلفة تشغيل الجهاز سنويًا', 'Annual Appliance Energy Cost Calculator', 'قدّر تكلفة تشغيل جهاز كهربائي سنويًا.', 'Estimate annual appliance operating cost.', '{"expression":"watts / 1000 * hours_per_day * 365 * electricity_price","outputUnitAr":" ر.س/سنة","outputUnitEn":" SAR/year","resultLabelAr":"التكلفة السنوية","resultLabelEn":"Annual energy cost","decimals":2,"showEquation":true}'::jsonb, '[{"key":"watts","label":"قدرة الجهاز بالواط","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_day","label":"ساعات التشغيل يوميًا","type":"number","required":true,"step":0.01,"min":0,"max":24},{"key":"electricity_price","label":"سعر الكيلوواط ساعة","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, '[{"key":"watts","label":"Appliance watts","type":"number","required":true,"step":0.01,"min":0},{"key":"hours_per_day","label":"Hours per day","type":"number","required":true,"step":0.01,"min":0,"max":24},{"key":"electricity_price","label":"Electricity price per kWh","type":"number","required":true,"step":0.01,"min":0}]'::jsonb, 'احسب النتيجة', 'Calculate', 2098, false),
  ('sustainability-tools', 'commute-carbon-emissions-calculator', 'حاسبة انبعاثات التنقل', 'Commute Carbon Emissions Calculator', 'قدّر انبعاثات التنقل من المسافة والأيام والمعامل.', 'Estimate commute emissions from distance, days, and factor.', '{"expression":"distance_per_day * commute_days * emission_factor","outputUnitAr":" كجم CO₂","outputUnitEn":" kg CO₂","resultLabelAr":"انبعاثات التنقل","resultLabelEn":"Commute emissions","decimals":2,"showEquation":true}'::jsonb, '[{"key":"distance_per_day","label":"المسافة اليومية بالكيلومتر","type":"number","required":true,"step":0.01,"min":0},{"key":"commute_days","label":"أيام التنقل","type":"number","required":true,"step":1,"min":0},{"key":"emission_factor","label":"معامل الانبعاث كجم/كم","type":"number","required":true,"step":0.01,"min":0,"defaultValue":0.192}]'::jsonb, '[{"key":"distance_per_day","label":"Daily distance in km","type":"number","required":true,"step":0.01,"min":0},{"key":"commute_days","label":"Commute days","type":"number","required":true,"step":1,"min":0},{"key":"emission_factor","label":"Emission factor kg/km","type":"number","required":true,"step":0.01,"min":0,"defaultValue":0.192}]'::jsonb, 'احسب النتيجة', 'Calculate', 2099, false);

do $$
declare
  v_seed_count integer;
  v_duplicate_count integer;
begin
  select count(*) into v_seed_count from wave2_formula_tool_seed;
  if v_seed_count <> 100 then
    raise exception 'WAVE2_TOOL_COUNT_MISMATCH:%', v_seed_count;
  end if;

  select count(*) - count(distinct slug)
  into v_duplicate_count
  from wave2_formula_tool_seed;

  if v_duplicate_count <> 0 then
    raise exception 'WAVE2_DUPLICATE_SLUGS:%', v_duplicate_count;
  end if;
end;
$$;

insert into public.tools(
  slug, title_ar, title_en, short_description, category_id, engine_type,
  input_schema, output_schema, runtime_config, pricing_mode, fixed_points,
  minimum_points, requires_auth, is_featured, is_active, sort_order,
  seo_title, seo_description
)
select
  seed.slug,
  seed.title_ar,
  seed.title_en,
  seed.description_ar,
  category.id,
  'formula',
  jsonb_build_object('submitLabel', seed.submit_ar, 'fields', seed.input_fields),
  jsonb_build_object('type', 'number', 'format', 'runtime'),
  seed.runtime_config,
  'free',
  0,
  0,
  false,
  seed.is_featured,
  true,
  seed.sort_order,
  seed.title_ar || ' مجانًا | أمبراطورية الويب',
  seed.description_ar
from wave2_formula_tool_seed seed
join public.categories category on category.slug = seed.category_slug
on conflict (slug) do update set
  title_ar = excluded.title_ar,
  title_en = excluded.title_en,
  short_description = excluded.short_description,
  category_id = excluded.category_id,
  engine_type = excluded.engine_type,
  input_schema = excluded.input_schema,
  output_schema = excluded.output_schema,
  runtime_config = excluded.runtime_config,
  pricing_mode = excluded.pricing_mode,
  fixed_points = excluded.fixed_points,
  minimum_points = excluded.minimum_points,
  requires_auth = excluded.requires_auth,
  is_featured = excluded.is_featured,
  is_active = excluded.is_active,
  sort_order = excluded.sort_order,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  updated_at = now();

insert into public.tool_translations(
  tool_id, locale_id, title, short_description, seo_title, seo_description,
  prompt_template_override
)
select
  tool.id,
  locale.id,
  case when locale.code = 'ar' then seed.title_ar else seed.title_en end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  case
    when locale.code = 'ar' then seed.title_ar || ' مجانًا | أمبراطورية الويب'
    else seed.title_en || ' Free | Web Empire'
  end,
  case when locale.code = 'ar' then seed.description_ar else seed.description_en end,
  null
from wave2_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id) do update set
  title = excluded.title,
  short_description = excluded.short_description,
  seo_title = excluded.seo_title,
  seo_description = excluded.seo_description,
  prompt_template_override = null,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  field.value ->> 'key',
  field.value ->> 'label',
  nullif(field.value ->> 'placeholder', ''),
  nullif(field.value ->> 'helpText', ''),
  field.value -> 'options'
from wave2_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
cross join lateral jsonb_array_elements(
  case when locale.code = 'ar' then seed.input_fields else seed.english_fields end
) field(value)
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  placeholder = excluded.placeholder,
  help_text = excluded.help_text,
  options = excluded.options,
  updated_at = now();

insert into public.tool_field_translations(
  tool_id, locale_id, field_key, label, placeholder, help_text, options
)
select
  tool.id,
  locale.id,
  '__submit__',
  case when locale.code = 'ar' then seed.submit_ar else seed.submit_en end,
  null, null, null
from wave2_formula_tool_seed seed
join public.tools tool on tool.slug = seed.slug
join public.locales locale on locale.code in ('ar', 'en')
on conflict (tool_id, locale_id, field_key) do update set
  label = excluded.label,
  updated_at = now();

do $$
declare
  r record;
begin
  for r in
    select
      category.slug,
      count(tool.id) filter (where tool.is_active) as active_tools
    from public.categories category
    left join public.tools tool on tool.category_id = category.id
    where category.slug in (
    'ecommerce-tools',
    'real-estate-tools',
    'travel-tools',
    'productivity-tools',
    'creator-tools',
    'sales-tools',
    'logistics-tools',
    'restaurant-tools',
    'freelancer-tools',
    'sustainability-tools'
    )
    group by category.slug
  loop
    if r.active_tools < 5 or r.active_tools > 50 then
      raise exception 'CATEGORY_TOOL_RANGE_VIOLATION:%:%', r.slug, r.active_tools;
    end if;
  end loop;
end;
$$;

commit;

